INSERT INTO cases (id, deleted, version, updated_at, data) VALUES ('case_mqzhgm5e_1k', 0, 1, '2026-05-30T17:19:55.682Z', '{"id":"case_mqzhgm5e_1k","ref":"EC-CASE-26-002","title":"Operative Disciplinary Tribunal — Probate","kind":"tribunal","clearance":"CL3","status":"ruled","summary":"Referral from Omega-1 command following a third active strike against the named operative. The Committee convened to determine whether the pattern warranted escalation.","respondentId":"usr_mqzhglxg_w","respondentName":null,"panelIds":["usr_mqzhglze_y","usr_mqzhgm1d_10"],"linkedSubjectIds":[],"summons":[{"id":"sum_mqzhgm5e_1l","ts":"2026-06-01T17:19:55.682Z","by":"EC-1","targetId":"usr_mqzhglxg_w","targetName":null,"reason":"Appear before the Committee to answer for repeated conduct infractions."}],"entries":[{"id":"ent_mqzhgm5e_1m","ts":"2026-05-30T17:19:55.682Z","by":"EC-1","type":"filing","text":"Case opened on referral from Omega-1 command."},{"id":"ent_mqzhgm5e_1n","ts":"2026-06-01T17:19:55.682Z","by":"EC-3","type":"testimony","text":"Respondent testimony heard; mitigating circumstances noted for the record."},{"id":"ent_mqzhgm5e_1o","ts":"2026-06-03T17:19:55.682Z","by":"EC-1","type":"ruling","text":"Panel ruling entered and served."}],"ruling":{"ts":"2026-06-03T17:19:55.682Z","by":"EC-1","finding":"upheld","rationale":"A pattern of infractions was established on the record and not adequately rebutted.","measures":"Final written warning; probation extended ninety days; reassignment review deferred pending conduct."},"createdBy":"EC-1","createdAt":"2026-05-30T17:19:55.682Z","updatedAt":"2026-05-30T17:19:55.682Z","version":1,"deleted":false,"deletedAt":null}');
